  CREATE TEMP TABLE tmp_business_analysis_source (
    legacy_business_analysis_id text PRIMARY KEY,
    analysis_date text,
    financial_analysis text,
    legacy_org_id text,
    strengths text,
    base_data text,
    title text,
    improvement_areas text,
    executive_summary text,
    growth_strategies text,
    business_score text,
    customer_analysis text,
    created_at text,
    updated_at text,
    created_by text
  ) ON COMMIT DROP;

  INSERT INTO tmp_business_analysis_source
  SELECT * FROM jsonb_to_recordset($business_analyses$[{"legacy_business_analysis_id":"698653ec283ed34a1dee71be","analysis_date":"2026-02-06T20:49:47.647Z","financial_analysis":"O lucro bruto de R$ 165.667,86 representa uma margem significativa em relação ao faturamento total, sugerindo uma boa gestão dos custos. É essencial, no entanto, monitorar continuamente os custos dos produtos e serviços para garantir que a margem continue estável e maximizar o lucro líquido.","legacy_org_id":"69864e74fb6fe137d3577c07","strengths":"[\"Faturamento total sólido de R$ 233.199,60 em 90 dias.\",\"Lucro bruto significativo de R$ 165.667,86.\",\"Ticket médio elevado de R$ 1.494,87 por ordem de serviço.\",\"Diversidade de serviços rentáveis, com destaque para serviços de alta margem como cabeçote retificado.\",\"Base de clientes cadastrados de 119, indicando uma boa chance de fidelização. \"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":156,\"faturamento_total\":233199.6,\"custo_total_produtos_servicos\":67531.73999999999,\"lucro_bruto\":165667.86000000002,\"ticket_medio_por_os\":1494.8692307692309,\"total_clientes_cadastrados\":119,\"top_5_servicos_rentaveis\":[\"CABEÇOTE RETIFICADO NA TROCA: R$ 13.010,00\",\"PISTÃO E ANEL: R$ 3.115,00\",\"VALVULA DE ESCAPE: R$ 3.060,00\",\"MONTAGEM COMPLETA: R$ 3.000,00\",\"VIRABREQUIM: R$ 2.900,00\"]}","title":"Análise de fevereiro de 2026","improvement_areas":"[\"Aumentar a taxa de recorrência entre os clientes.\",\"Aumentar o número total de clientes cadastrados.\",\"Uma análise mais detalhada dos serviços menos rentáveis.\",\"Capacitação da equipe em técnicas de vendas e atendimento ao cliente.\",\"Implementar um sistema de feedback para entender melhor as necessidades dos clientes.\"]","executive_summary":"Nos últimos 90 dias, a oficina apresentou um desempenho sólido com um faturamento total de R$ 233.199,60 e um lucro bruto de R$ 165.667,86, resultando em uma margem de lucro saudável. O ticket médio por ordem de serviço é de R$ 1.494,87, indicando um bom potencial de receita. Apesar dos resultados positivos, há espaço para otimizações e crescimento, especialmente na fidelização de clientes e na diversificação de serviços.","growth_strategies":"[{\"titulo\":\"Criar pacotes de revisão para clientes recorrentes\",\"descricao\":\"Oferecer pacotes de serviços de manutenção com desconto para os 10 clientes mais frequentemente atendidos, incentivando a fidelização e o aumento do ticket médio.\"},{\"titulo\":\"Iniciar campanha de marketing direcionada\",\"descricao\":\"Lançar uma campanha no Instagram focada em serviços de ar condicionado, que têm margens de lucro altas, para atrair novos clientes durante os meses de calor.\"},{\"titulo\":\"Desenvolver um programa de fidelidade\",\"descricao\":\"Implantar um programa de pontos que recompensa clientes por indicações ou por cada serviço realizado, estimulando a base de clientes e gerando novos negócios.\"},{\"titulo\":\"Oferecer treinamentos técnicos para a equipe\",\"descricao\":\"Investir em capacitação para a equipe em novas técnicas e tendências do mercado automotivo, melhorando a qualidade do serviço e a satisfação do cliente.\"},{\"titulo\":\"Explorar serviços complementares e acessórios\",\"descricao\":\"Adicionar serviços relacionados, como instalação de acessórios, que podem ser oferecidos aos clientes durante a manutenção, ampliando o faturamento.\"}]","business_score":"82","customer_analysis":"Com 119 clientes cadastrados, a oficina apresenta uma boa base para desenvolvimento de relacionamentos de longo prazo. Focar na retenção e fidelização através de boas práticas de atendimento e programas de fidelidade pode trazer um aumento considerável em repetição de negócios.","created_at":"2026-02-06T20:49:48.193000","updated_at":"2026-02-16T12:35:56.885000","created_by":"marquesmd9@gmail.com"},{"legacy_business_analysis_id":"6967777f3d7a7616f07b4e8f","analysis_date":"2026-01-14T11:01:19.228Z","financial_analysis":"A análise financeira mostra um modelo de negócio saudável, com um lucro bruto considerável e um ticket médio promissor. No entanto, o total de clientes cadastrados é um ponto fraco que, se não abordado, pode limitar o crescimento. O foco deve ser na captação de clientes e na ampliação da base de clientes que gere um fluxo de caixa mais robusto.","legacy_org_id":"69864ce67137a313e5c26d4d","strengths":"[\"Faturamento total de R$39.701,14 em 90 dias, indicando uma demanda estável.\",\"Lucro bruto de R$24.607,11, demonstrando boa rentabilidade.\",\"Ticket médio de R$844,71 por ordem de serviço, o que sugere preços acima da média de mercado.\",\"Serviços de mão de obra se destacam como as principais fontes de receita, proporcionando alta margem de lucro.\",\"A diversificação dos serviços prestados, incorporando produtos e peças, aumenta a oferta aos clientes.\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":47,\"faturamento_total\":39701.14,\"custo_total_produtos_servicos\":15094.030000000002,\"lucro_bruto\":24607.109999999997,\"ticket_medio_por_os\":844.7051063829787,\"total_clientes_cadastrados\":11,\"top_5_servicos_rentaveis\":[\"MAO DE OBRA: R$ 5.130,00\",\"MÃO DE OBRA: R$ 4.130,00\",\"INTERCOOLER: R$ 1.428,30\",\"RETIFICA: R$ 1.200,00\",\"MOTOR PARTIDA FOX/POLO/GOL G5/: R$ 1.061,10\"]}","title":"Análise de janeiro de 2026","improvement_areas":"[\"Número de clientes cadastrados ainda é baixo (apenas 11), limitando o potencial de receita.\",\"Aumentar o número de ordens de serviço poderia ajudar a melhorar a escala do negócio.\",\"Explorar mais serviços que atendam a demanda local e as tendências do mercado automotivo.\",\"Melhorar a comunicação e marketing para atrair novos clientes e reter os existentes.\",\"Implementar um programa de fidelidade para aumentar a retenção de clientes e o ticket médio.\"]","executive_summary":"A análise do desempenho da oficina mecânica nos últimos 90 dias revela resultados encorajadores, com um faturamento total de R$39.701,14 e um lucro bruto de R$24.607,11. O ticket médio por ordem de serviço é satisfatório, mas a baixa quantidade de clientes cadastrados sugere uma oportunidade de crescimento. Com um foco nas áreas identificadas, a oficina pode elevar ainda mais sua rentabilidade e ampliar sua base de clientes.","growth_strategies":"[{\"titulo\":\"Campanha de fidelização de clientes\",\"descricao\":\"Criar um programa de fidelidade que ofereça descontos, serviços gratuitos após um certo número de visitas ou pacotes de manutenção a preços especiais para os 10 clientes mais recorrentes.\"},{\"titulo\":\"Marketing digital focado em redes sociais\",\"descricao\":\"Iniciar uma campanha no Instagram e Facebook destacando serviços específicos, como ar condicionado e serviços rápidos, que têm alta margem e são de interesse dos clientes.\"},{\"titulo\":\"Parcerias com empresas locais\",\"descricao\":\"Estabelecer parcerias com empresas de frota ou concessionárias locais para ser a oficina oficial para manutenção, garantindo volume de ordens de serviço.\"},{\"titulo\":\"Pacotes de serviços e promoções sazonais\",\"descricao\":\"Oferecer pacotes de revisão e manutenção a preços promocionais durante períodos de alta demanda, como verão e inverno, para incentivar visitas.\"},{\"titulo\":\"Feedback e avaliação de clientes\",\"descricao\":\"Implementar uma pesquisa de satisfação após os serviços para coletar feedback e identificar áreas de melhoria, além de impulsionar a confiança da clientela.\"}]","business_score":"78","customer_analysis":"A base de clientes, com apenas 11 cadastrados, indica que a oficina ainda não explorou seu mercado potencial. É crucial investir em estratégias de marketing e relacionamento com clientes para aumentar essa base. A promoção de serviços e a fidelização dos existentes devem ser priorizadas.","created_at":"2026-01-14T11:01:19.593000","updated_at":"2026-02-16T12:36:06.405000","created_by":"contato@loker.com.br"},{"legacy_business_analysis_id":"6908b7f7538cf012b0ca8cca","analysis_date":"2025-11-03T14:11:02.608Z","financial_analysis":"O faturamento total de R$ 26.447,04 e o custo total de produtos e serviços de R$ 9.456,80 resultam em um lucro bruto de R$ 16.990,24, o que demonstra uma boa margem de lucro. Entretanto, é necessário aumentar o volume de serviços para diluir custos e melhorar ainda mais a rentabilidade.","legacy_org_id":"69864ce67137a313e5c26d4d","strengths":"[\"Lucro bruto elevado (R$ 16.990,24) proporcionando bons índices de rentabilidade.\",\"Ticket médio por ordem de serviço que demonstra potencial para serviços de maior valor.\",\"Diversidade de serviços rentáveis com foco em mão de obra e componentes específicos, como motores e porta-caroneiros.\",\"Baixo custo total de produtos e serviços (R$ 9.456,80) em relação ao faturamento.\",\"Uma lista clara dos 5 serviços mais rentáveis, permitindo melhor focagem nos esforços de vendas.\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":30,\"faturamento_total\":26447.04,\"custo_total_produtos_servicos\":9456.8,\"lucro_bruto\":16990.24,\"ticket_medio_por_os\":881.568,\"total_clientes_cadastrados\":10,\"top_5_servicos_rentaveis\":[\"MAO DE OBRA: R$ 4.380,00\",\"RETIFICA: R$ 1.200,00\",\"MOTOR PARTIDA FOX/POLO/GOL G5/: R$ 1.061,10\",\"PORTA CARONEIRO DIANTEIRO: R$ 980,00\",\"MÃO DE OBRA: R$ 810,00\"]}","title":"Análise de novembro de 2025","improvement_areas":"[\"Aumentar a base de clientes cadastrados, atualmente apenas 10.\",\"Melhorar a frequência de retorno dos clientes para serviços contínuos.\",\"Diferenciar as estratégias de marketing para alcançar novos segmentos de mercado.\",\"Desenvolver pacotes promocionais para atrair novos clientes e incentivar a fidelização.\",\"Análise mais detalhada de cada serviço para identificar oportunidades de aumento de preços ou agregação de valor.\"]","executive_summary":"A análise dos últimos 90 dias da oficina mecânica demonstra uma performance sólida com um faturamento total de R$ 26.447,04 e um lucro bruto de R$ 16.990,24, resultando em um ticket médio por ordem de serviço de R$ 881,57. Com apenas 10 clientes cadastrados, a capacidade de expansão é alta. O negócio mostra potencial, mas há necessidade de otimização na base de clientes e no crescimento das vendas.","growth_strategies":"[{\"titulo\":\"Campanha de Fidelização de Clientes\",\"descricao\":\"Criar pacotes de revisão e manutenção para os 10 clientes mais recorrentes, garantindo um fluxo de receita mais estável.\"},{\"titulo\":\"Promoção Sazonal para Serviços\",\"descricao\":\"Oferecer descontos ou promoções em serviços de alta margem, como ar condicionado, especialmente em períodos quentes.\"},{\"titulo\":\"Marketing Digital Focado\",\"descricao\":\"Iniciar uma campanha no Instagram e Facebook para promover serviços como a retífica e motores, utilizando imagens de antes e depois.\"},{\"titulo\":\"Parcerias Locais\",\"descricao\":\"Estabelecer parcerias com empresas locais, como locadoras de veículos ou empresas de ônibus, para serviços regulares de manutenção.\"},{\"titulo\":\"Treinamento e Capacitação da Equipe\",\"descricao\":\"Promover treinamentos regulares para a equipe, aumentando a eficiência e a qualidade do atendimento, o que pode refletir em maior satisfação e fidelização dos clientes.\"}]","business_score":"81","customer_analysis":"A oficina conta com apenas 10 clientes cadastrados, o que representa uma oportunidade significativa para crescimento. A criação de programas de fidelidade e pacotes promocionais pode ajudar a atrair e manter novos clientes, além de incrementar o número de ordens de serviço.","created_at":"2025-11-03T14:11:03.028000","updated_at":"2026-02-16T12:36:06.459000","created_by":"contato@loker.com.br"},{"legacy_business_analysis_id":"68ffcc830858c8e5e0bc2840","analysis_date":"2025-10-27T19:48:18.847Z","financial_analysis":"O faturamento total de R$ 19.702,9 e o custo de R$ 8.071,49 resultam em um lucro bruto considerável, indicando que o negócio está operando de forma eficiente em relação aos custos. O ticket médio de R$ 788,11 é um bom sinal de que os clientes estão envolvidos com os serviços oferecidos, mas há espaço para melhorar a captação de novos clientes e aumentar o volume de vendas.","legacy_org_id":"69864ce67137a313e5c26d4d","strengths":"[\"Lucro bruto saudável de R$ 11.631, indicando boa rentabilidade.\",\"Ticket médio de R$ 788,11 sugere que os clientes estão dispostos a gastar.\",\"Diversidade de serviços oferecidos, com foco em mão de obra e assistência técnica.\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":25,\"faturamento_total\":19702.9,\"custo_total_produtos_servicos\":8071.49,\"lucro_bruto\":11631.410000000002,\"ticket_medio_por_os\":788.1160000000001,\"total_clientes_cadastrados\":8,\"top_5_servicos_rentaveis\":[\"MAO DE OBRA: R$ 2.730,00\",\"RETIFICA: R$ 1.200,00\",\"MOTOR PARTIDA FOX/POLO/GOL G5/: R$ 1.061,10\",\"PORTA CARONEIRO DIANTEIRO: R$ 980,00\",\": R$ 800,00\"]}","title":"Análise de outubro de 2025","improvement_areas":"[\"Aumentar o número de clientes cadastrados; apenas 8 clientes ativos podem limitar o crescimento.\",\"As ordens de serviço estão relativamente baixas; melhorar a captação de serviços pode ser uma prioridade.\",\"Explorar novas estratégias de marketing digital para aumentar a visibilidade e atrair novos clientes.\"]","executive_summary":"Com um total de 25 ordens de serviço nos últimos 90 dias e um faturamento de aproximadamente R$ 19.703, a oficina apresenta um bom desempenho, com um lucro bruto significativo de R$ 11.631. As principais áreas que impulsionam os lucros são serviços de mão de obra e reparos específicos, indicando um potencial de crescimento através da fidelização e da satisfação do cliente.","growth_strategies":"[{\"titulo\":\"Fidelização de Clientes\",\"descricao\":\"Criar um programa de fidelidade que ofereça descontos em serviços para clientes que retornam, incentivando a recorrência.\"},{\"titulo\":\"Campanhas de Marketing Digital\",\"descricao\":\"Iniciar uma campanha no Instagram focada em serviços de ar condicionado e elétrica, já que esses serviços têm alta margem.\"},{\"titulo\":\"Pacotes de Serviços\",\"descricao\":\"Desenvolver pacotes de revisão e manutenção para os 10 clientes mais frequentes, com um preço fixo que inclua várias operações.\"},{\"titulo\":\"Parcerias Locais\",\"descricao\":\"Estabelecer parcerias com empresas locais (ex: frotas de empresas, escolas ou pequenas empresas) que precisam de manutenção regular para veículos.\"},{\"titulo\":\"Workshops e Demonstrações\",\"descricao\":\"Realizar workshops mensais gratuitos sobre manutenção de veículos, gerando interesse e trazendo novos clientes para o negócio.\"}]","business_score":"80","customer_analysis":"Com apenas 8 clientes cadastrados, a oficina deve focar em estratégias de marketing e relacionamento para ampliar a base de clientes. A baixa quantidade de ordens de serviço (25) sugere que um trabalho em rede, promoções e atendimentos personalizados podem ajudar a atrair e reter clientes.","created_at":"2025-10-27T19:48:19.741000","updated_at":"2026-02-16T12:36:06.417000","created_by":"contato@loker.com.br"},{"legacy_business_analysis_id":"68f6b3e18f9ba8567bce3444","analysis_date":"2025-10-20T22:12:49.325Z","financial_analysis":"A análise financeira aponta um perfil de lucratividade saudável, com um lucro bruto significativo em relação ao faturamento total. A estrutura de custos deverá ser melhor controlada para maximizar o lucro. Monitorar de perto as despesas operacionais e buscar parcerias para redução de custos pode ser crucial para aumentar a margem de lucro.","legacy_org_id":"","strengths":"[\"Alto ticket médio (R$ 2.204,87) indicando serviços de maior valor\",\"Lucro bruto positivo (R$ 30.159,40) mostrando viabilidade financeira\",\"Diversificação em serviços prestados com opções de alta margem de lucro\",\"Experiência e expertise em serviços técnicos especializados\",\"Capacidade de realizar serviços complexos como retífica de cabeçote completa\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":25,\"faturamento_total\":55121.65,\"custo_total_produtos_servicos\":24962.25,\"lucro_bruto\":30159.4,\"ticket_medio_por_os\":2204.866,\"total_clientes_cadastrados\":5,\"top_5_servicos_rentaveis\":[\"MOTOR LAND ROVER - PISTAO LAND ROVER: R$ 16.000,00\",\"MOTOR LAND ROVER - BIELA LAND ROVER: R$ 10.400,00\",\"Retífica de Cabeçote Completa - Mão de Obra Especializada: R$ 8.940,00\",\"Kit Revisão 10000km - Óleo Motor 5W30: R$ 4.590,00\",\"Retífica de Cabeçote Completa - Bielas: R$ 3.840,00\"]}","title":"Análise de outubro de 2025","improvement_areas":"[\"Base de clientes muito reduzida (apenas 5 cadastrados)\",\"Falta de promoção e visibilidade online dos serviços prestados\",\"Necessidade de aprimorar a retenção de clientes\",\"Exploração de canais de marketing digital ainda não utilizada\",\"Reduzir o custo total de produtos e serviços através de parcerias estratégicas\"]","executive_summary":"Analisando o desempenho da oficina mecânica nos últimos 90 dias, observa-se um faturamento total de R$ 55.121,65, com um lucro bruto de R$ 30.159,40. Apesar de um ticket médio de R$ 2.204,87, a base de clientes é limitada, com apenas 5 clientes cadastrados, o que impacta diretamente na capacidade de crescimento do negócio. É crucial avaliar e implementar estratégias para não apenas aumentar a base de clientes mas também a rentabilidade dos serviços prestados.","growth_strategies":"[{\"titulo\":\"Campanha de Indicação de Clientes\",\"descricao\":\"Criar um programa de indicações onde clientes que tragam novos clientes ganham descontos em serviços ou incentivos financeiros.\"},{\"titulo\":\"Pacotes de Serviços Personalizados\",\"descricao\":\"Oferecer pacotes de revisão e manutenção com preços especiais para os 10 clientes mais recorrentes.\"},{\"titulo\":\"Marketing Digital Focado\",\"descricao\":\"Iniciar uma campanha no Instagram destacando serviços de alta margem como ar condicionado e retífica de cabeçote, com promoções mensais.\"},{\"titulo\":\"Parcerias Locais\",\"descricao\":\"Formar parcerias com empresas locais que possam indicar a oficina, como concessionárias e lojas de autopeças.\"},{\"titulo\":\"Oficinas Abertas para Clientes\",\"descricao\":\"Realizar eventos de portas abertas, mostrando serviços oferecidos e promovendo diálogos sobre a manutenção preventiva dos veículos.\"}]","business_score":"76","customer_analysis":"A análise da base de clientes revela uma oportunidade significativa de crescimento. Com apenas 5 clientes cadastrados, o esforço deve ser direcionado para a aquisição e retenção de novos clientes. A implementação de estratégias de marketing digital e programas de fidelidade são recomendadas para aumentar a recorrência e a satisfação dos clientes.","created_at":"2025-10-20T22:12:49.805000","updated_at":"2025-10-20T22:12:49.805000","created_by":"beenkoficial@gmail.com"},{"legacy_business_analysis_id":"68f68002d7129cd1cd5a6f8f","analysis_date":"2025-10-20T18:31:29.815Z","financial_analysis":"A análise financeira revela que o negócio tem uma estrutura saudável, com lucro bruto expressivo. O ticket médio de R$ 1.935,44, apesar do baixo volume de ordens de serviço, indica que serviços diferenciados estão sendo bem aceitos. É crucial, no entanto, diversificar a oferta para estabilizar o faturamento em períodos menos movimentados.","legacy_org_id":"69864ce67137a313e5c26d4d","strengths":"[\"Alto lucro bruto, com 57% de margem sobre o custo total.\",\"Oferta de serviços rentáveis, especialmente em veículos de marcas específicas como Land Rover e Ford.\",\"Ticket médio elevado, indicando um bom potencial de receita por atendimento.\",\"Experiência e especialização em serviços mecânicos, o que pode diferenciar a oficina da concorrência.\",\"Capacidade de atender a um nicho de mercado com alta demanda e baixo número de concorrentes diretos.\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":49,\"faturamento_total\":94836.55,\"custo_total_produtos_servicos\":40622.99,\"lucro_bruto\":54213.560000000005,\"ticket_medio_por_os\":1935.4397959183675,\"total_clientes_cadastrados\":12,\"top_5_servicos_rentaveis\":[\"MOTOR LAND ROVER - PISTAO LAND ROVER: R$ 16.000,00\",\"MOTOR LAND ROVER - BIELA LAND ROVER: R$ 10.400,00\",\"Kit Revisão 10000km - Óleo Motor 5W30: R$ 9.180,00\",\"CABEÇOTE FORD KA 3C - Válvulas de Admissão Ford Ka 3c: R$ 9.120,00\",\"Retífica de Cabeçote Completa - Mão de Obra Especializada: R$ 8.940,00\"]}","title":"Análise de outubro de 2025","improvement_areas":"[\"Número reduzido de clientes cadastrados (apenas 12), indicando necessidade de expansão da base.\",\"Menor volume de ordens de serviço, que sugere oportunidades de aumento de frequência de atendimento.\",\"Dependência de poucos serviços para a maior parte do faturamento, o que pode representar risco em casos de queda de demanda em um desses segmentos.\",\"Melhorar estratégias de marketing para aumentar a visibilidade da oficina.\",\"Optimizar o gerenciamento de estoque para evitar custos desnecessários e agregar valor ao serviço. \"]","executive_summary":"Nos últimos 90 dias, a oficina apresentou um desempenho financeiro sólido, com um total de 49 ordens de serviço e um faturamento total de R$ 94.836,55. O lucro bruto de R$ 54.213,56 demonstra uma boa margem de lucro, reforçada por um ticket médio saudável. Apesar do número reduzido de clientes cadastrados, a oficina tem se destacado em serviços de alta rentabilidade, especialmente com peças e serviços relacionados a veículos específicos.","growth_strategies":"[{\"titulo\":\"Expandir a base de clientes\",\"descricao\":\"Criar promoções e pacotes de revisão para os 10 clientes mais recorrentes, incentivando-os a trazer novos clientes.\"},{\"titulo\":\"Fortalecer a presença digital\",\"descricao\":\"Iniciar campanhas no Instagram focadas em serviços de alta margem, como ar condicionado e serviços especializados para modelos específicos.\"},{\"titulo\":\"Educar o cliente\",\"descricao\":\"Oferecer workshops ou seminários sobre manutenção básica de veículos, o que pode posicionar a oficina como referência e aumentar a fidelidade do cliente.\"},{\"titulo\":\"Programa de fidelidade\",\"descricao\":\"Implementar um sistema de pontos ou descontos para clientes frequentes, incentivando a repetição de serviços.\"},{\"titulo\":\"Parcerias estratégicas\",\"descricao\":\"Estabelecer parcerias com empresas locais de seguros ou frotas para garantir um fluxo consistente de serviços.\"}]","business_score":"78","customer_analysis":"A análise dos clientes mostra que existem apenas 12 clientes cadastrados, o que destaca uma necessidade urgente de expandir a base. Estratégias de retenção e atração de novos clientes devem ser prioridades para garantir o crescimento contínuo e a sustentabilidade da oficina.","created_at":"2025-10-20T18:31:30.493000","updated_at":"2026-02-16T12:36:06.405000","created_by":"contato@loker.com.br"},{"legacy_business_analysis_id":"68d99fb8bafb77edec3cf752","analysis_date":"2025-09-28T20:51:03.554Z","financial_analysis":"O lucro bruto de R$ 50.457,76 demonstra que a oficina tem um potencial sólido em termos de rentabilidade. O custo total de produtos e serviços, de R$ 38.175,55, sugere que a gestão de custos pode ser otimizada para aumentar ainda mais a margem de lucro. O total de faturamento é satisfatório para um número reduzido de ordens de serviço, revelando que um foco em estratégias de fidelização e diversificação é essencial.","legacy_org_id":"69864ce67137a313e5c26d4d","strengths":"[\"Alta margem nos serviços de motores e retificações, destacando-se na lucratividade.\",\"Ticket médio elevado, acima da média do setor.\",\"Faturamento total expressivo considerando o número limitado de clientes.\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":38,\"faturamento_total\":88633.30999999998,\"custo_total_produtos_servicos\":38175.549999999996,\"lucro_bruto\":50457.75999999999,\"ticket_medio_por_os\":2332.455526315789,\"total_clientes_cadastrados\":10,\"top_5_servicos_rentaveis\":[\"MOTOR LAND ROVER - PISTAO LAND ROVER: R$ 16.000,00\",\"MOTOR LAND ROVER - BIELA LAND ROVER: R$ 10.400,00\",\"Kit Revisão 10000km - Óleo Motor 5W30: R$ 9.180,00\",\"CABEÇOTE FORD KA 3C - Válvulas de Admissão Ford Ka 3c: R$ 9.120,00\",\"Retífica de Cabeçote Completa - Mão de Obra Especializada: R$ 8.940,00\"]}","title":"Análise de setembro de 2025","improvement_areas":"[\"Baixa quantidade de clientes cadastrados, apenas 10.\",\"Dependência elevada de serviços específicos, o que pode impactar a variabilidade de receita.\",\"Necessidade de diversificar a oferta de serviços para atrair diferentes perfis de clientes.\"]","executive_summary":"O desempenho da oficina nos últimos 90 dias mostra uma consistência razoável, com um lucro bruto significativo e um ticket médio autêntico. Com um total de 38 ordens de serviço, a oficina alcançou um faturamento considerável, evidenciando oportunidades de crescimento através da ampliação da base de clientes e do aumento na frequência de serviços oferecidos aos clientes cadastrados.","growth_strategies":"[{\"titulo\":\"Fidelização de Clientes Frequentes\",\"descricao\":\"Criar pacotes de revisão e manutenção para os 10 clientes mais recorrentes, incentivando visitas periódicas e aumentando o ticket médio.\"},{\"titulo\":\"Campanha de Marketing Digital\",\"descricao\":\"Iniciar uma campanha no Instagram focada em serviços de ar condicionado e manutenção de motores, que têm alta margem e ampla demanda.\"},{\"titulo\":\"Parcerias Locais\",\"descricao\":\"Estabelecer parcerias com empresas de frota ou carros de aluguel para serviços regulares, garantindo um fluxo adicional de ordens de serviço.\"},{\"titulo\":\"Ofertas Sazonais\",\"descricao\":\"Criar promoções e descontos em serviços de verão ou inverno, como ar condicionado e aquecedores, para estimular visitas durante períodos específicos.\"},{\"titulo\":\"Cursos e Workshops\",\"descricao\":\"Realizar workshops educativos para os clientes sobre manutenção preventiva e cuidados com o carro, criando uma comunidade em torno da oficina.\"}]","business_score":"78","customer_analysis":"A base de clientes é restrita a apenas 10 clientes cadastrados, o que limita o crescimento. Estratégias visando a aquisição de novos clientes e o aumento da frequência de serviços devem ser priorizadas. O ticket médio de R$ 2.332,46 é encorajador, mas para garantir a sustentabilidade, é crucial desenvolver relacionamentos duradouros com os clientes, transformando-os em recorrentes.","created_at":"2025-09-28T20:51:04.050000","updated_at":"2026-02-16T12:36:06.471000","created_by":"contato@loker.com.br"},{"legacy_business_analysis_id":"68d2b2f46cae26ed34ad8a05","analysis_date":"2025-09-23T14:47:15.448Z","financial_analysis":"O desempenho financeiro mostra uma margem de lucro saudável de aproximadamente 57%, o que é um bom sinal para a viabilidade do negócio. O controle sobre os custos de produtos e serviços é fundamental, e a análise dos serviços mais rentáveis pode ajudar a definir prioridades para ações futuras.","legacy_org_id":"69864ce67137a313e5c26d4d","strengths":"[\"Bom faturamento total e lucro bruto para o volume de ordens\",\"Ticket médio por ordem de serviço acima da média do setor\",\"Serviços altamente rentáveis, especialmente em veículos de marcas premium como Land Rover e Ford\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":38,\"faturamento_total\":88633.30999999998,\"custo_total_produtos_servicos\":38175.549999999996,\"lucro_bruto\":50457.75999999999,\"ticket_medio_por_os\":2332.455526315789,\"total_clientes_cadastrados\":10,\"top_5_servicos_rentaveis\":[\"MOTOR LAND ROVER - PISTAO LAND ROVER: R$ 16.000,00\",\"MOTOR LAND ROVER - BIELA LAND ROVER: R$ 10.400,00\",\"Kit Revisão 10000km - Óleo Motor 5W30: R$ 9.180,00\",\"CABEÇOTE FORD KA 3C - Válvulas de Admissão Ford Ka 3c: R$ 9.120,00\",\"Retífica de Cabeçote Completa - Mão de Obra Especializada: R$ 8.940,00\"]}","title":"Análise de setembro de 2025","improvement_areas":"[\"Baixa quantidade de clientes cadastrados (apenas 10)\",\"Necessidade de diversificar os serviços prestados para atrair diferentes nichos de clientes\",\"Melhoria na comunicação e marketing para aumentar a visibilidade da oficina\"]","executive_summary":"Nos últimos 90 dias, a oficina teve um desempenho positivo, com um faturamento total de R$ 88.633,31 e um lucro bruto de R$ 50.457,76. O ticket médio por ordem de serviço foi de R$ 2.332,46, o que é um bom indicador para o negócio, considerando a quantidade de serviços prestados e a rentabilidade. A base de clientes ainda é limitada, com apenas 10 clientes cadastrados, o que sugere que há espaço significativo para crescimento. É crucial melhorar a captação de novos clientes e a fidelização dos existentes.","growth_strategies":"[{\"titulo\":\"Fidelização de Clientes\",\"descricao\":\"Criar pacotes de revisão e manutenção para os 10 clientes mais recorrentes, oferecendo benefícios como desconto em serviços adicionais ou um programa de pontos para cada serviço realizado.\"},{\"titulo\":\"Campanha de Mídia Social\",\"descricao\":\"Iniciar uma campanha no Instagram focada em serviços que têm alta margem de lucro, como ar condicionado, destacando promoções e serviços especializados, para atrair um público mais jovem e engajado.\"},{\"titulo\":\"Parcerias Locais\",\"descricao\":\"Estabelecer parcerias com empresas locais e concessionárias para serviços de manutenção e reparo, oferecendo descontos a clientes indicados.\"},{\"titulo\":\"Capacitação da Equipe\",\"descricao\":\"Investir em treinamentos para a equipe sobre atendimento ao cliente e habilidades técnicas avançadas para melhorar a qualidade do serviço.\"},{\"titulo\":\"Promoções Temporárias\",\"descricao\":\"Desenvolver ofertas sazonais, como descontos em serviços para veículos de férias, que incentivem os clientes a procurar a oficina em períodos específicos.\"}]","business_score":"78","customer_analysis":"A base de clientes é limitada, sugerindo que a oficina deve se concentrar em estratégias de marketing e relacionamento para ampliar o seu alcance e a fidelização. A diversificação dos serviços e a personalização das ofertas podem ajudar a criar uma melhor conexão com clientes potencialmente valiosos.","created_at":"2025-09-23T14:47:16.196000","updated_at":"2026-02-16T12:36:06.439000","created_by":"contato@loker.com.br"},{"legacy_business_analysis_id":"68d20ba1f7182dabf8310b0d","analysis_date":"2025-09-23T02:53:20.801Z","financial_analysis":"O faturamento total de R$ 88.633,31, com um custo de produtos e serviços de R$ 38.175,55, resulta em um lucro bruto saudável. Isso demonstra um modelo de negócios eficaz na forma como atua, mas deve ser acompanhado por controle de custos e aumento da geração de receita.","legacy_org_id":"","strengths":"[\"Lucro bruto elevado de R$ 50.457,76 em comparação ao custo total.\",\"Ticket médio de R$ 2.332,46, indicando um bom valor por atendimento.\",\"Diversidade de serviços rentáveis, com destaque para serviços de alto valor como motores Land Rover.\",\"Um total de 38 ordens de serviço em 90 dias, mostrando um fluxo constante de trabalho.\"]","base_data":"{\"periodo_analise\":\"últimos 90 dias (ou desde o início)\",\"total_ordens_servico\":38,\"faturamento_total\":88633.30999999998,\"custo_total_produtos_servicos\":38175.549999999996,\"lucro_bruto\":50457.75999999999,\"ticket_medio_por_os\":2332.455526315789,\"total_clientes_cadastrados\":10,\"top_5_servicos_rentaveis\":[\"MOTOR LAND ROVER - PISTAO LAND ROVER: R$ 16.000,00\",\"MOTOR LAND ROVER - BIELA LAND ROVER: R$ 10.400,00\",\"Kit Revisão 10000km - Óleo Motor 5W30: R$ 9.180,00\",\"CABEÇOTE FORD KA 3C - Válvulas de Admissão Ford Ka 3c: R$ 9.120,00\",\"Retífica de Cabeçote Completa - Mão de Obra Especializada: R$ 8.940,00\"]}","title":"Análise de setembro de 2025","improvement_areas":"[\"Base de clientes muito reduzida com apenas 10 clientes cadastrados.\",\"Potencial para criação de pacotes e promoções para serviços oferecidos.\",\"Estratégias de marketing digital e fidelização de clientes precisam ser aprimoradas.\",\"Aumentar a visibilidade e a presença online da oficina.\",\"Falta de serviços adicionais que poderiam melhorar a média de faturamento por cliente.\"]","executive_summary":"Análise dos últimos 90 dias revela que a oficina está operando de forma rentável, com um lucro bruto significativo e um ticket médio consistente. No entanto, a base de clientes é limitada, o que fornece uma oportunidade clara para expansão e aumento do volume de negócios.","growth_strategies":"[{\"titulo\":\"Fidelização de Clientes com Programas de Pontos\",\"descricao\":\"Implementar um programa de fidelidade onde os clientes acumulem pontos a cada serviço, que podem ser trocados por descontos ou serviços gratuitos.\"},{\"titulo\":\"Pacotes de Serviços e Promoções\",\"descricao\":\"Criar pacotes de revisões e manutenção preventiva para os 10 clientes mais recorrentes, incentivando visitas regulares.\"},{\"titulo\":\"Campanha de Marketing Digital\",\"descricao\":\"Iniciar uma campanha no Instagram focada em serviços de ar condicionado, que tem alta margem, para aumentar a visibilidade e atrair novos clientes.\"},{\"titulo\":\"Parcerias com Concessionárias e Vendedores de Veículos\",\"descricao\":\"Estabelecer parcerias com concessionárias locais para ser o centro de manutenção recomendado, aumentando a referência e garantindo mais ordens de serviço.\"},{\"titulo\":\"Aprimoramento do Atendimento ao Cliente\",\"descricao\":\"Treinamento da equipe para maximizar a experiência do cliente, resultando em sentimento positivo e recomendações boca-a-boca.\"}]","business_score":"78","customer_analysis":"Com apenas 10 clientes cadastrados, a oficina apresenta uma baixa penetração de mercado. O foco deve ser na retenção de clientes e na aquisição de novos, através de estratégias de marketing e promoção de serviços.","created_at":"2025-09-23T02:53:21.327000","updated_at":"2025-09-23T02:53:21.327000","created_by":"beenkoficial@gmail.com"}]$business_analyses$::jsonb) AS src(
    legacy_business_analysis_id text,
    analysis_date text,
    financial_analysis text,
    legacy_org_id text,
    strengths text,
    base_data text,
    title text,
    improvement_areas text,
    executive_summary text,
    growth_strategies text,
    business_score text,
    customer_analysis text,
    created_at text,
    updated_at text,
    created_by text
  );

